const Maybe = (value) => ({
  map: (fn) => Maybe(value == null ? null : fn(value)),
  chain: (fn) => (value == null ? Maybe(null) : fn(value)),
  get: () => value,
});

const result = Maybe(5)
  .map((x) => x * 2)
  .chain((x) => Maybe(x + 1));

console.log(result.get()); // 11

