const safeDivide = (divisor) => (x) =>
  divisor === 0 ? Maybe(null) : Maybe(x / divisor);

const result = Maybe(10)
  .chain(safeDivide(0))   // division by 0 -> null
  .map((x) => x + 5);     // skipped because value is null

console.log(result.get()); // null

function orderPizza(price, coupon, balance) {
  if (price == null) {
    return "No price";
  }

  const finalPrice = price - coupon;

  if (finalPrice < 0) {
    return "Invalid discount";
  }

  if (balance < finalPrice) {
    return "Not enough money";
  }

  return `Pizza ordered for ${finalPrice}`;
}

const Maybe = (value) => ({
  map: (fn) => Maybe(value == null ? null : fn(value)),
  chain: (fn) => (value == null ? Maybe(null) : fn(value)),
  get: () => value,
});

const safeSubtract = (a, b) =>
  b > a ? Maybe(null) : Maybe(a - b);

const safePay = (balance) => (price) =>
  balance < price ? Maybe(null) : Maybe(`Pizza ordered for ${price}`);

const result = Maybe(20)
  .chain((price) => safeSubtract(price, 5))
  .chain(safePay(15));

console.log(result.get()); // "Pizza ordered for 15"

const Validator = (value, error = null) => ({
  map: (fn) => (error ? Validator(value, error) : Validator(fn(value))),
  chain: (fn) => (error ? Validator(value, error) : fn(value)),
  isValid: () => !error,
  getError: () => error,
  getValue: () => value,
});

const success = (value) => Validator(value);
const failure = (error) => Validator(null, error);

const validateName = (user) =>
  user.name && user.name.length >= 2
    ? success(user)
    : failure("Name too short");

const validateEmail = (user) =>
  /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(user.email)
    ? success(user)
    : failure("Invalid email");

const validateAge = (user) =>
  user.age >= 18
    ? success(user)
    : failure("Must be at least 18");

const validateUser = (user) =>
  success(user)
    .chain(validateName)
    .chain(validateEmail)
    .chain(validateAge);

console.log(
  validateUser({ name: "Anna", email: "anna@example.com", age: 25 }).isValid()
); // true

console.log(
  validateUser({ name: "A", email: "anna@example.com", age: 25 }).getError()
); // "Name too short"

console.log(
  validateUser({ name: "Anna", email: "bad-email", age: 25 }).getError()
); // "Invalid email"

console.log(
  validateUser({ name: "Anna", email: "anna@example.com", age: 15 }).getError()
); // "Must be at least 18"

const Maybe = (value) => ({
  chain: (fn) => (value == null ? Maybe(null) : fn(value)),
  get: () => value,
});

const f = (x) => Maybe(x + 1);
const g = (x) => Maybe(x * 2);

const left = Maybe(5).chain(f).chain(g).get();
const right = Maybe(5).chain((x) => f(x).chain(g)).get();

console.log(left);  // 12
console.log(right); // 12
